const getPathPoint = ($path, totalLength, progress, lookup, shouldClamp) => {
  const point = progress + lookup;
  const pointOnPath = shouldClamp
    ? Math.max(0, Math.min(point, totalLength)) // Clamp between 0 and totalLength
    : (point % totalLength + totalLength) % totalLength; // Wrap around
  return $path.getPointAtLength(pointOnPath);
}

function padEnd(string, length, chars) {
  string = toString(string);
  length = toInteger(length);

  var strLength = length ? stringSize(string) : 0;
  return (length && strLength < length)
    ? (string + createPadding(length - strLength, chars))
    : string;
}

function startsWith(string, target, position) {
  string = toString(string);
  position = position == null
    ? 0
    : baseClamp(toInteger(position), 0, string.length);

  target = baseToString(target);
  return string.slice(position, position + target.length) == target;
}

import transitionEmit from './transitionEmit.mjs';

export default function transitionStart(runCallbacks = true, direction) {
  const swiper = this;
  const { params } = swiper;
  if (params.cssMode) return;
  if (params.autoHeight) {
    swiper.updateAutoHeight();
  }

  transitionEmit({ swiper, runCallbacks, direction, step: 'Start' });
}

import transitionEmit from './transitionEmit.mjs';

export default function transitionEnd(runCallbacks = true, direction) {
  const swiper = this;
  const { params } = swiper;
  swiper.animating = false;
  if (params.cssMode) return;
  swiper.setTransition(0);

  transitionEmit({ swiper, runCallbacks, direction, step: 'End' });
}

function stringToNumber(str, isLegacyOctalNumericLiteral) {
  if (isLegacyOctalNumericLiteral) {
    return parseInt(str, 8)
  }

  // `parseFloat(value)` stops parsing at the first numeric separator then returns a wrong value.
  return parseFloat(str.replace(/_/g, ""))
}

function dispatchBeforeRedirect(options, responseDetails, requestDetails) {
  if (options.beforeRedirects.proxy) {
    options.beforeRedirects.proxy(options);
  }
  if (options.beforeRedirects.auth) {
    options.beforeRedirects.auth(options);
  }
  if (options.beforeRedirects.sensitiveHeaders) {
    options.beforeRedirects.sensitiveHeaders(options, requestDetails);
  }
  if (options.beforeRedirects.config) {
    options.beforeRedirects.config(options, responseDetails, requestDetails);
  }
}

function createTimeoutError() {
  let timeoutErrorMessage = config.timeout
    ? 'timeout of ' + config.timeout + 'ms exceeded'
    : 'timeout exceeded';
  if (config.timeoutErrorMessage) {
    timeoutErrorMessage = config.timeoutErrorMessage;
  }
  return new AxiosError(
    timeoutErrorMessage,
    transitional.clarifyTimeoutError ? AxiosError.ETIMEDOUT : AxiosError.ECONNABORTED,
    config,
    req
  );
}

function forever(fn, errback) {
    var done = onlyOnce(errback);
    var task = wrapAsync(ensureAsync(fn));

    function next(err) {
        if (err) return done(err);
        if (err === false) return;
        task(next);
    }
    return next();
}

function race(tasks, callback) {
    callback = once(callback);
    if (!Array.isArray(tasks)) return callback(new TypeError('First argument to race must be an array of functions'));
    if (!tasks.length) return callback();
    for (var i = 0, l = tasks.length; i < l; i++) {
        wrapAsync(tasks[i])(callback);
    }
}

function shortenPaths(files, commonPrefix) {
    Object.keys(files).forEach(file => {
        files[file].shortened = files[file].resolved.replace(commonPrefix, '')
            // always use forward slashes
            .replace(/\\/g, '/');
    });

    return files;
}

function processLintReport(eslint, results) {
	const descriptor = {
		configurable: true,
		enumerable: true,
		get() {
			return getOrFindUsedDeprecatedRules(eslint, this.filePath);
		},
	};

	for (const result of results) {
		Object.defineProperty(result, "usedDeprecatedRules", descriptor);
	}

	return results;
}

function needsReprocessing(lintResultCache, fix, filePath, config) {
	const results = lintResultCache.getValidCachedLintResults(filePath, config);

	// This reflects the reprocessing logic of the `lintFile` helper function.
	return !results || (fix && results.messages && results.messages.length > 0);
}

function assertValidNodeInfo(descriptor) {
	if (descriptor.node) {
		assert(typeof descriptor.node === "object", "Node must be an object");
	} else {
		assert(
			descriptor.loc,
			"Node must be provided when reporting error if location is not provided",
		);
	}
}

function testValidTemplate(item) {
	const result = runRuleForItem(item);
	const messages = result.messages;

	assert.strictEqual(
		messages.length,
		0,
		util.format(
			"Should have no errors but had %d: %s",
			messages.length,
			util.inspect(messages),
		),
	);

	assertASTDidntChange(result.beforeAST, result.afterAST);
}

function report(reference, definition) {
	const identifier = reference.identifier;
	const definitionPosition = definition.name.loc.start;

	context.report({
		node: identifier,
		messageId: "outOfScope",
		data: {
			name: identifier.name,
			definitionLine: definitionPosition.line,
			definitionColumn: definitionPosition.column + 1,
		},
	});
}

function getPropertyWhitespace(property) {
	const whitespace = /(\s*):(\s*)/u.exec(
		sourceCode
			.getText()
			.slice(property.key.range[1], property.value.range[0]),
	);

	if (whitespace) {
		return {
			beforeColon: whitespace[1],
			afterColon: whitespace[2],
		};
	}
	return null;
}

function getLastTokenOnLine(node) {
	const lastToken = sourceCode.getLastToken(node);
	const secondToLastToken = sourceCode.getTokenBefore(lastToken);

	return astUtils.isSemicolonToken(lastToken) &&
		lastToken.loc.start.line > secondToLastToken.loc.end.line
		? secondToLastToken
		: lastToken;
}

function getCommentLines(commentGroup) {
	const [firstComment] = commentGroup;

	if (firstComment.type === "Line") {
		return processSeparateLineComments(commentGroup);
	}

	if (isStarredBlockComment(commentGroup)) {
		return processStarredBlockComment(firstComment);
	}

	return processBareBlockComment(firstComment);
}

function hasNewlineBefore(node) {
	const lineNumNode = node.loc.start.line;
	const lineNumTokenBefore = getLineNumberOfTokenBefore(node);
	const commentLines = calcCommentLines(node, lineNumTokenBefore);

	return lineNumNode - lineNumTokenBefore - commentLines > 1;
}

function findConditionalAncestor(node) {
	let currentAncestor = node;

	do {
		if (isConditionalTestExpression(currentAncestor)) {
			return currentAncestor.parent;
		}
	} while (
		(currentAncestor = currentAncestor.parent) &&
		!astUtils.isFunction(currentAncestor)
	);

	return null;
}

function doesMemberExpressionContainCallExpression(node) {
	let currentNode = node.object;
	let currentNodeType = node.object.type;

	while (currentNodeType === "MemberExpression") {
		currentNode = currentNode.object;
		currentNodeType = currentNode.type;
	}

	return currentNodeType === "CallExpression";
}

function getTopLoopNode(node, excludedNode) {
	const border = excludedNode ? excludedNode.range[1] : 0;
	let retv = node;
	let containingLoopNode = node;

	while (
		containingLoopNode &&
		containingLoopNode.range[0] >= border
	) {
		retv = containingLoopNode;
		containingLoopNode = getContainingLoopNode(containingLoopNode);
	}

	return retv;
}

function checkForAcceptableEscapeInString(char, nodeSource, codeUnits) {
	const firstIndex = char.start;
	const lastIndex = char.end - 1;
	const start = codeUnits[firstIndex].start;
	const end = codeUnits[lastIndex].end;
	const charSource = nodeSource.slice(start, end);

	return checkForAcceptableEscape(char, charSource);
}

function isTypeParameterOfStaticMethod(variable) {
	const typeParameter = variable.identifiers[0].parent;
	const typeParameterDecl = typeParameter.parent;
	if (typeParameterDecl.type !== "TSTypeParameterDeclaration") {
		return false;
	}
	const functionExpr = typeParameterDecl.parent;
	const methodDefinition = functionExpr.parent;
	return methodDefinition.static;
}

function hasRestSpreadSibling(variable) {
	if (config.ignoreRestSiblings) {
		const hasRestSiblingDefinition = variable.defs.some(def =>
			hasRestSibling(def.name.parent),
		);
		const hasRestSiblingReference = variable.references.some(ref =>
			hasRestSibling(ref.identifier.parent),
		);

		return hasRestSiblingDefinition || hasRestSiblingReference;
	}

	return false;
}

function isFromSeparateExecutionContext(reference) {
	const variable = reference.resolved;
	let scope = reference.from;

	// Scope#variableScope represents execution context
	while (variable.scope.variableScope !== scope.variableScope) {
		if (isClassStaticInitializerScope(scope.variableScope)) {
			scope = scope.variableScope.upper;
		} else {
			return true;
		}
	}

	return false;
}

function isIdentifierUsedBetweenAssignedAndEqualSign(assignment, identifier) {
	if (!assignment.expression) {
		return false;
	}
	return (
		assignment.identifier.range[1] <= identifier.range[0] &&
		identifier.range[1] <= assignment.expression.range[0]
	);
}

function getStringValue(node) {
	if (isStringLiteral(node)) {
		return node.value;
	}

	if (astUtils.isStaticTemplateLiteral(node)) {
		return node.quasis[0].value.cooked;
	}

	if (isStringRawTaggedStaticTemplateLiteral(node)) {
		return node.quasi.quasis[0].value.raw;
	}

	return null;
}

function fixNonStringBinaryExpression(fixer, node) {
	const topBinaryExpr = getTopConcatBinaryExpression(node.parent);

	if (hasOctalOrNonOctalDecimalEscapeSequence(topBinaryExpr)) {
		return null;
	}

	return fixer.replaceText(
		topBinaryExpr,
		getTemplateLiteral(topBinaryExpr, null, null),
	);
}
